CREATE INDEX "assets_public_browse_idx" ON "assets" USING btree ("image_date","id") WHERE "assets"."status" = 'APPROVED' and "assets"."visibility" = 'PUBLIC' and "assets"."media_type" = 'IMAGE' and "assets"."r2_exists" = true;--> statement-breakpoint
CREATE INDEX "assets_public_category_idx" ON "assets" USING btree ("category_id","image_date","id") WHERE "assets"."status" = 'APPROVED' and "assets"."visibility" = 'PUBLIC' and "assets"."media_type" = 'IMAGE' and "assets"."r2_exists" = true;--> statement-breakpoint
CREATE INDEX "assets_public_event_idx" ON "assets" USING btree ("event_id","image_date","id") WHERE "assets"."status" = 'APPROVED' and "assets"."visibility" = 'PUBLIC' and "assets"."media_type" = 'IMAGE' and "assets"."r2_exists" = true;--> statement-breakpoint
CREATE INDEX "assets_public_photographer_idx" ON "assets" USING btree ("photographer_profile_id","image_date","id") WHERE "assets"."status" = 'APPROVED' and "assets"."visibility" = 'PUBLIC' and "assets"."media_type" = 'IMAGE' and "assets"."r2_exists" = true;--> statement-breakpoint
CREATE INDEX "assets_public_sort_idx" ON "assets" USING btree (coalesce("image_date", "created_at"), "id") WHERE "assets"."status" = 'APPROVED' and "assets"."visibility" = 'PUBLIC' and "assets"."media_type" = 'IMAGE' and "assets"."r2_exists" = true;--> statement-breakpoint
CREATE INDEX "assets_public_search_text_gin_idx" ON "assets" USING gin (to_tsvector('english', coalesce("search_text", ''))) WHERE "assets"."status" = 'APPROVED' and "assets"."visibility" = 'PUBLIC' and "assets"."media_type" = 'IMAGE' and "assets"."r2_exists" = true;--> statement-breakpoint
